import json, sqlite3, os

def parse_lines(text, repo):
    results = []
    seen = set()
    for line in text.strip().split('\n'):
        line = line.strip().lstrip('#')
        if not line or '|' not in line:
            continue
        parts = line.split('|')
        if len(parts) < 5:
            continue
        try:
            num = int(parts[0].strip())
        except ValueError:
            continue
        if num in seen:
            continue
        seen.add(num)
        is_bug = 1 if parts[1].strip().lower() == 'yes' else 0
        root_cause = parts[2].strip()
        bug_cat = parts[3].strip()
        svc_area = parts[4].strip()
        url = f"https://github.com/Azure/azure-sdk-for-{repo}/issues/{num}"
        row_id = f"{repo}_{num}"
        results.append((row_id, repo, num, url, is_bug, root_cause, bug_cat, svc_area, 0, '', ''))
    return results

