# ============ Write to consolidated SQLite ============
db_path = "/tmp/final_classifications.db"
if os.path.exists(db_path):
    os.remove(db_path)

conn = sqlite3.connect(db_path)
c = conn.cursor()
c.execute("""CREATE TABLE IF NOT EXISTS classifications (
    id TEXT PRIMARY KEY,
    repo TEXT,
    issue_number INTEGER,
    url TEXT,
    is_actual_bug INTEGER,
    root_cause TEXT,
    bug_category TEXT,
    service_area TEXT,
    batch_num INTEGER DEFAULT 0,
    state TEXT DEFAULT '',
    title TEXT DEFAULT ''
)""")

# Insert Python
c.executemany("INSERT OR IGNORE INTO classifications VALUES (?,?,?,?,?,?,?,?,?,?,?)", py_rows)
print(f"Inserted {c.rowcount} Python rows")

# Insert .NET and Go (they have 11-element tuples)
for row in net_data + go_data:
    c.execute("INSERT OR IGNORE INTO classifications VALUES (?,?,?,?,?,?,?,?,?,?,?)", tuple(row))
print(f"Inserted .NET + Go: {len(net_data) + len(go_data)} rows")

conn.commit()

# Check counts
c.execute("SELECT repo, COUNT(*) FROM classifications GROUP BY repo")
for row in c.fetchall():
    print(f"  {row[0]}: {row[1]}")

c.execute("SELECT COUNT(*) FROM classifications")
print(f"Total so far (no JS, no Java): {c.fetchone()[0]}")
